import React, { useState } from 'react';
import DragDropCanvas from './components/DragDropCanvas';
import VisualizationLibrary from './components/VisualizationLibrary';
import ExportManager from './components/ExportManager';
import DataConnections from './components/DataConnections';
import { WindowPanel, BackgroundConfig, DataConnection } from './types';
import './App.css';

const App: React.FC = () => {
  const [windows, setWindows] = useState<WindowPanel[]>([]);
  const [backgroundConfig, setBackgroundConfig] = useState<BackgroundConfig>({
    width: 1200,
    height: 800,
    color: '#ffffff'
  });
  const [dataConnections, setDataConnections] = useState<DataConnection>({
    apiConnections: [],
    globalVariables: {}
  });
  const [activeTab, setActiveTab] = useState<'builder' | 'data'>('builder');

  const handleAddTemplate = (type: 'javascript' | 'html', template: any) => {
    const newWindow: WindowPanel = {
      id: `window-${Date.now()}`,
      title: template.name,
      type,
      content: type === 'html' ? template.code : '',
      position: { 
        x: Math.random() * 300 + 50, 
        y: Math.random() * 200 + 50 
      },
      size: { width: 400, height: 300 },
      jsCode: type === 'javascript' ? template.code : undefined
    };

    setWindows(prev => [...prev, newWindow]);
  };

  const handleWindowsChange = (newWindows: WindowPanel[]) => {
    setWindows(newWindows);
  };

  return (
    <div style={{
      height: '100vh',
      display: 'flex',
      flexDirection: 'column',
      fontFamily: 'Arial, sans-serif'
    }}>
      {/* Header */}
      <header style={{
        padding: '15px 20px',
        backgroundColor: '#343a40',
        color: 'white',
        borderBottom: '1px solid #dee2e6'
      }}>
        <h1 style={{ 
          margin: 0, 
          fontSize: '24px',
          fontWeight: 'normal'
        }}>
          🏗️ Website Builder - Drag & Drop Visualizations
        </h1>
        <p style={{ 
          margin: '5px 0 0 0', 
          fontSize: '14px', 
          opacity: 0.8 
        }}>
          Create interactive web applications with JavaScript and HTML windows
        </p>
      </header>

      {/* Main Layout */}
      <div style={{
        flex: 1,
        display: 'flex',
        overflow: 'hidden'
      }}>
        {/* Left Sidebar - Templates */}
        <div style={{
          width: '280px',
          backgroundColor: '#f8f9fa',
          borderRight: '1px solid #dee2e6',
          overflow: 'auto'
        }}>
          <VisualizationLibrary onAddTemplate={handleAddTemplate} />
        </div>

        {/* Center - Canvas */}
        <div style={{ flex: 1 }}>
          <DragDropCanvas 
            windows={windows}
            onWindowsChange={handleWindowsChange}
            backgroundConfig={backgroundConfig}
            onBackgroundConfigChange={setBackgroundConfig}
          />
        </div>

        {/* Right Sidebar - Export */}
        <div style={{
          width: '280px',
          backgroundColor: '#f8f9fa',
          borderLeft: '1px solid #dee2e6',
          overflow: 'auto'
        }}>
          <ExportManager 
            windows={windows} 
            backgroundConfig={backgroundConfig}
            onBackgroundConfigChange={setBackgroundConfig}
          />
        </div>
      </div>
    </div>
  );
};

export default App;
